#include<bits/stdc++.h>
using namespace std;
int main(){
    long long n,m,ans=0,ans2=0;
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(i==j){
                ans+=((n-i+1)*(m-j+1));
            }else{
                ans2+=((n-i+1)*(m-j+1));
            }
        }
    }
    cout<<ans<<" "<<ans2;
    return 0;
}
